class ExampleServicer:
    def __init__(self):
        self.internal_state = InternalState()
        self.data_store = {}
    
    @handle_service_error
    def GetData(self, request, context):
        key = request.key
        
        if not key:
            raise ValueError("Key cannot be empty")
        
        if key not in self.data_store:
            raise FileNotFoundError(f"Key '{key}' not found in data store")
        
        response = type('Response', (), {})()
        response.value = self.data_store[key]
        response.success = True
        return response
    
    @handle_service_error
    def SetData(self, request, context):
        key = request.key
        value = request.value
        
        if not key:
            raise ValueError("Key cannot be empty")
        
        if len(key) > 100:
            raise ValueError("Key length exceeds maximum of 100 characters")
        
        self.data_store[key] = value
        
        response = type('Response', (), {})()
        response.success = True
        response.message = f"Data set successfully for key: {key}"
        return response
    
    @handle_service_error
    def ProcessData(self, request, context):
        operation = request.operation
        data = request.data
        
        if operation == "divide_by_zero":
            result = 1 / 0
        elif operation == "access_invalid_key":
            result = self.data_store["nonexistent_key"]
        elif operation == "raise_permission":
            raise PermissionError("Insufficient permissions for this operation")
        elif operation == "timeout":
            raise TimeoutError("Operation timed out after 30 seconds")
        elif operation == "process":
            result = data * 2
        else:
            raise ValueError(f"Unknown operation: {operation}")
        
        response = type('Response', (), {})()
        response.result = result
        response.success = True
        return response
    
    @handle_service_error
    def GetHealth(self, request, context):
        state = self.internal_state.get_state()
        
        response = type('Response', (), {})()
        response.status = "healthy"
        response.details = json.dumps(state)
        return response
    
    @handle_service_error
    def StreamData(self, request_iterator, context):
        for request in request_iterator:
            try:
                self.internal_state.increment_request()
                
                if request.value < 0:
                    raise ValueError("Value must be non-negative")
                
                response = type('Response', (), {})()
                response.processed_value = request.value * 2
                response.success = True
                yield response
                
            except Exception as e:
                error_msg = f"Stream processing error: {str(e)}"
                self.internal_state.increment_error(error_msg)
                error_details = create_error_details(e, self.internal_state, "StreamData", request)
                context.set_code(grpc.StatusCode.INTERNAL)
                context.set_details(error_details)
                raise grpc.RpcError(error_details)


class GenericExceptionInterceptor(grpc.ServerInterceptor):
    def __init__(self, internal_state):
        self.internal_state = internal_state
    
    def intercept_service(self, continuation, handler_call_details):
        try:
            return continuation(handler_call_details)
        except Exception as e:
            error_details = {
                'timestamp': datetime.now().isoformat(),
                'method': handler_call_details.method,
                'error_type': type(e).__name__,
                'error_message': str(e),
                'stack_trace': traceback.format_exc(),
                'internal_state': self.internal_state.get_state() if self.internal_state else {}
            }
            
            def error_handler(request, context):
                context.set_code(grpc.StatusCode.UNKNOWN)
                context.set_details(json.dumps(error_details, indent=2))
                raise grpc.RpcError(json.dumps(error_details))
            
            return grpc.unary_unary_rpc_method_handler(
                error_handler,
                request_deserializer=handler_call_details.method,
                response_serializer=handler_call_details.method
            )


def serve():
    servicer = ExampleServicer()
    interceptor = GenericExceptionInterceptor(servicer.internal_state)
    
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        interceptors=(interceptor,),
        options=[
            ('grpc.max_send_message_length', 50 * 1024 * 1024),
            ('grpc.max_receive_message_length', 50 * 1024 * 1024),
        ]
    )
    
    server.add_insecure_port('[::]:50051')
    server.start()
    print("Server started on port 50051")
    
    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        server.stop(0)


class ErrorLoggingServicer:
    def __init__(self, log_file='service_errors.log'):
        self.internal_state = InternalState()
        self.log_file = log_file
        self.lock = threading.Lock()
    
    def log_error(self, error_details):
        with self.lock:
            with open(self.log_file, 'a') as f:
                f.write(f"\n{'='*80}\n")
                f.write(error_details)
                f.write(f"\n{'='*80}\n")
    
    @handle_service_error
    def ExecuteTask(self, request, context):
        task_id = request.task_id
        task_type = request.task_type
        
        try:
            if task_type == "critical":
                if task_id % 2 == 0:
                    raise RuntimeError(f"Critical task {task_id} failed due to system error")
            elif task_type == "validation":
                if task_id < 0:
                    raise ValueError(f"Invalid task_id: {task_id}")
            else:
                pass
            
            response = type('Response', (), {})()
            response.task_id = task_id
            response.status = "completed"
            response.success = True
            return response
            
        except Exception as e:
            error_details = create_error_details(e, self.internal_state, "ExecuteTask", request)
            self.log_error(error_details)
            raise


